  'tea-031': {
    en: { name: 'OPA', description: 'Orange Pekoe A. Characterized by bold, large, slightly open leaves. Brews into a very mild, pale liquor with a soothing, earthy flavor.' },
    es: { name: 'Té OPA', description: 'Orange Pekoe A. Caracterizado por hojas audaces, grandes y ligeramente abiertas. Produce un licor muy suave y pálido con un sabor terroso y tranquilizador.' },
    fr: { name: 'Thé OPA', description: 'Orange Pekoe A. Caractérisé par des feuilles audacieuses, grandes et légèrement ouvertes. Produit un liquide très léger et pâle avec une saveur terreuse et apaisante.' },
    it: { name: 'Tè OPA', description: 'Orange Pekoe A. Caratterizzato da foglie audaci, grandi e leggermente aperte. Produce un liquore molto delicato e pallido con un sapore terroso e confortante.' },
    ru: { name: 'Чай ОПА', description: 'Orange Pekoe A. Крупные, слегка раскрытые листья. Даёт очень мягкий, бледный настой с успокаивающим, землистым вкусом.' },
    ja: { name: 'OPAティー', description: 'オレンジペコーA。大きくほんのり開いた力強い葉が特徴。とても穏やかで淡い水色と、落ち着いたアーシーな風味をもたらします。' },
    zh: { name: 'OPA茶', description: '橙白毫A。以大而略开的粗壮叶片为特征。冲泡出极为清淡的茶汤，带有舒缓的土感风味。' },
  },
